func worker(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {
  defer wg.Done()
  for j := range jobs {
    results <- j * j
  }
}

func main() {
  jobs := make(chan int, 10)
  results := make(chan int, 10)
  var wg sync.WaitGroup
  for w := 1; w <= 3; w++ {
    wg.Add(1)
    go worker(w, jobs, results, &wg)
  }
  for j := 1; j <= 9; j++ { jobs <- j }
  close(jobs)
  wg.Wait()
  close(results)
}

